record.field:
base_url = env['ir.config_parameter'].sudo().get_param('web.base.url', '')
webhook_url = f"{base_url}/telegram/webhook"
result = env['telegram.bot'].set_webhook(webhook_url)
if result:
    action = {
        'type': 'ir.actions.client',
        'tag': 'display_notification',
        'params': {
            'title': 'Webhook',
            'message': f'Webhook configured: {webhook_url}',
            'type': 'success',
        },
    }
else:
    action = {
        'type': 'ir.actions.client',
        'tag': 'display_notification',
        'params': {
            'title': 'Error',
            'message': 'Failed to set webhook. Check the bot token.',
            'type': 'danger',
        },
    }
